import os
import shutil
import sys
import subprocess
import tarfile
import zipfile

def create_backup(source_dir, backup_format):
    if not os.path.exists(source_dir):
        print("Source directory does not exist.")
        return

    backup_file = f"{source_dir.rstrip('/')}.backup.{backup_format}"
    
    if backup_format == 'tar.gz':
        with tarfile.open(backup_file, 'w:gz') as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
    elif backup_format == 'tar.bz2':
        with tarfile.open(backup_file, 'w:bz2') as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
    elif backup_format == 'zip':
        with zipfile.ZipFile(backup_file, 'w', zipfile.ZIP_DEFLATED) as zipf:
            for root, dirs, files in os.walk(source_dir):
                for file in files:
                    zipf.write(os.path.join(root, file), 
                                os.path.relpath(os.path.join(root, file), 
                                                os.path.join(source_dir, '..')))
    elif backup_format == '7z':
        if shutil.which('7z') is not None:
            subprocess.run(['7z', 'a', backup_file, source_dir])
        else:
            print("7z is not installed or not available in PATH.")
            return
    else:
        print("Unsupported backup format.")
        return

    print(f"Backup created: {backup_file}")

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <format>")
        sys.exit(1)

    directory_path = sys.argv[1]
    format_choice = sys.argv[2]
    
    create_backup(directory_path, format_choice)